<template>
    <section id="hompageCarousel" class="carousel slide carousel-fade" data-bs-ride="carousel">
        <div class="carousel-indicators" >
          <button type="button" data-bs-target="#hompageCarousel" v-for="(imgCnt, i) in imgArray" :key="'imgCnt-' + imgCnt.id" :data-bs-slide-to="imgCnt.id" :aria-label="imgCnt.id" :class="{ 'active': i === active }"></button>
        </div>
        <div class="carousel-inner" >
          <div v-for="(heroImg, index) in imgArray" 
              :key="'heroImg-' + heroImg.id" 
              :class="{ 'carousel-item' : true, 'active': index === active  }">
              <img :src="heroImg.imgSrc" class="d-block w-100" style="object-fit: cover;" alt="Hero Image">
          </div>
      
        </div>
        <button class="carousel-control-prev" type="button" data-bs-target="#hompageCarousel" data-bs-slide="prev">
          <span class="carousel-control-prev-icon" aria-hidden="true"></span>
          <span class="visually-hidden">Previous</span>
        </button>
        <button class="carousel-control-next" type="button" data-bs-target="#hompageCarousel" data-bs-slide="next">
          <span class="carousel-control-next-icon" aria-hidden="true"></span>
          <span class="visually-hidden">Next</span>
        </button>
      </section>
</template>

<script>
    export default {
        name: 'CarouselCmpt',
        data(){
            return ({ 
                imgArray: [
                    { id: 0, imgSrc: 'https://placeimg.com/1000/400/arch', desc: 'desc'},
                    { id: 1, imgSrc: 'https://placeimg.com/1000/400/people', desc: 'desc'},
                    { id: 2, imgSrc: 'https://placeimg.com/1000/400/tech', desc: 'desc'},
                    { id: 3, imgSrc: 'https://placeimg.com/1000/400/animals', desc: 'desc'},
                    { id: 4, imgSrc: 'https://placeimg.com/1000/400/nature', desc: 'desc'}
                ],
                active: 0
                
            })
        },
        methods:{
          setActive(index){
            let active = index;

            if(index === this.imgArray.length) active = 0;
            else if(index === -1) active = this.imgArray.length -1;

            this.active = active;
          }
        }
    }
</script>